interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  name: string;
  type?: string;
}

export default function Input({ name, type = 'text', ...props }: InputProps) {
  return (
    <>
      <input
        className="rounded-md border border-gray/10 font-roboto-flex dark:border-white/10 placeholder:text-gray/50 dark:placeholder:text-white/50 bg-white/10 dark:bg-black/10 px-4 py-3 text-gray dark:text-white focus:border-blue focus:outline-none focus:ring-1 focus:ring-blue w-full transition"
        id={name}
        name={name}
        type={type}
        {...props}
        required
      />
    </>
  );
}
