'use client';
import { useFormStatus } from 'react-dom';
import { type ComponentProps } from 'react';
import { Circle } from 'lucide-react';

type Props = ComponentProps<'button'> & {
  pendingText?: string;
};

export default function SubmitButton({
  children,
  pendingText,
  ...props
}: Props) {
  const { pending } = useFormStatus();

  return (
    <button className='bg-primary' {...props} type="submit" aria-disabled={pending}>
      {pending ? <Circle className="animate-spin" /> :  <Circle className="animate-spin"/>}
    </button>
  );
}
